mapper.select:
SELECT u.name AS studentName, s.name AS subjectName, l.day_of_week AS dayOfWeek, l.start_time AS startTime, l.end_time AS endTime, c.name AS classroomName, a.attend_date AS attendDate, a.status AS status FROM payment p INNER JOIN student_enrollment se ON p.enrollment_id = se.enrollment_id INNER JOIN user u ON se.student_id = u.user_id INNER JOIN lecture l ON se.lecture_id = l.lecture_id INNER JOIN subject s ON s.subject_id = l.subject_id INNER JOIN classroom c ON l.classroom_id = c.classroom_id INNER JOIN attendance a ON p.payment_id = a.payment_id WHERE se.lecture_id IN ( SELECT lecture_id FROM teacher_assignment WHERE teacher_id = #{teacherId} )
AND ( u.name LIKE CONCAT('%', #{keyword}, '%') OR s.name LIKE CONCAT('%', #{keyword}, '%') )
AND DATE(a.attend_date) = #{searchDate}
ORDER BY a.attend_date DESC LIMIT #{startRow}, #{rowPerPage}

mapper.update:
UPDATE attendance
SET status = #{status}
WHERE attendance_id = #{attendanceId}

mapper.insert:
INSERT INTO attendance (payment_id, attend_date, status) SELECT p.payment_id, -- 수강 결제 ID CURDATE(), -- 오늘 날짜 '결석' -- 기본 출석 상태 FROM payment p JOIN student_enrollment se ON p.enrollment_id = se.enrollment_id WHERE se.lecture_id IN
#{id}
AND NOT EXISTS ( SELECT 1 FROM attendance a WHERE a.payment_id = p.payment_id AND a.attend_date = CURDATE() -- 이미 오늘 출석이 기록되어 있으면 제외 )

mapper.select:
SELECT COUNT(*) FROM payment p INNER JOIN student_enrollment se ON p.enrollment_id = se.enrollment_id INNER JOIN user u ON se.student_id = u.user_id INNER JOIN lecture l ON se.lecture_id = l.lecture_id INNER JOIN subject s ON s.subject_id = l.subject_id INNER JOIN attendance a ON p.payment_id = a.payment_id WHERE se.lecture_id IN ( SELECT lecture_id FROM teacher_assignment WHERE teacher_id = #{teacherId} )
AND ( u.name LIKE CONCAT('%', #{keyword}, '%') OR s.name LIKE CONCAT('%', #{keyword}, '%') OR a.status LIKE CONCAT('%', #{keyword}, '%') )
AND DATE(a.attend_date) = #{searchDate}
